        $tools_dir = __DIR__;
        $storage_dir = dirname($tools_dir);    // storage/agent
        $agent_dir = dirname($storage_dir);    // storage
        $project_root = dirname($agent_dir);   // project root
        $workspace_dir = $storage_dir . DIRECTORY_SEPARATOR . 'workspace';
        $db_path = $workspace_dir . DIRECTORY_SEPARATOR . $db_name;

