        $chart_fn = 'chart_' . time() . '.png';
        $chart_path = $workspace_dir . DIRECTORY_SEPARATOR . $chart_fn;
        $report_path = $workspace_dir . DIRECTORY_SEPARATOR . $report_fn;

        try {
            // Phase 1: SQL
            $pdo = new PDO("sqlite:{$db_path}");
            $pdo->setAttribute(PDO::ATTR_ERRMODE, PDO::ERRMODE_EXCEPTION);
            $stmt = $pdo->prepare($sql);
            $stmt->execute($params);
            $rows = $stmt->fetchAll(PDO::FETCH_NUM);
            if (count($rows) === 0) return ['error' => 'Query returned no rows'];
            if (count($rows[0]) < 2) return ['error' => 'Need 2 columns'];
            
            $labels = array_map(fn($r) => (string)$r[0], $rows);
            $values = array_map(fn($r) => (float)$r[1], $rows);
            $total_rows = count($rows);
            if (count($labels) > $max_rows) { $labels = array_slice($labels, 0, $max_rows); $values = array_slice($values, 0, $max_rows); }
            
            // Phase 2: Chart via GD
            if (!extension_loaded('gd')) return ['error' => 'GD not loaded'];
            
            $cw = min(800, max(400, count($labels) * 38 + 80));
