            imagefill($img,0,0,$bg);
            $ml=60;$mr=20;$mt=50;$mb=45;$pw=$cw-$ml-$mr;$ph=$ch-$mt-$mb;
            
            $tlen = strlen($chart_title);
            $tfont = $tlen > 30 ? 2 : 5;
            $tx = max(2, (int)(($cw - $tlen * imagefontwidth($tfont))/2));
