            $mv = max(array_map('abs',$values)); if($mv==0)$mv=1;
            $scale = $ph/$mv;
            
            for($i=0;$i<=5;$i++){
                $gy=(int)($mt+$ph-($ph*$i/5));
                imageline($img,$ml,$gy,$cw-$mr,$gy,$gc);
                $v=$mv*$i/5;
                $vl=$v>=1000000?round($v/1000000,1).'M':($v>=1000?round($v/1000,1).'K':(int)$v);
                imagestring($img,1,5,$gy-4,(string)$vl,$ax);
            }
            
            $nc = count($values);
            $bw = max(3,min(35,(int)(($pw-10)/$nc-2)));
            $sp = max(2,min(4,(int)(($pw-$bw*$nc)/($nc+1))));
            $x=$ml+$sp;
            
            for($i=0;$i<$nc;$i++){
                $bh=(int)($values[$i]*$scale);
                $by=$mt+$ph-$bh;
                imagefilledrectangle($img,$x,$by,$x+$bw,$mt+$ph,$bc);
                imagerectangle($img,$x,$by,$x+$bw,$mt+$ph,$bd);
                $lb=strlen($labels[$i])>6?substr($labels[$i],0,5).'.':$labels[$i];
                $lx=(int)($x+($bw-strlen($lb)*imagefontwidth(1))/2);
                imagestring($img,1,max($x,$lx),$mt+$ph+3,$lb,$tc);
                $x+=$bw+$sp;
            }
            
            imageline($img,$ml,$mt,$ml,$mt+$ph,$ax);
            imageline($img,$ml,$mt+$ph,$cw-$mr,$mt+$ph,$ax);
            imagepng($img,$chart_path);
            imagedestroy($img);
            $chart_size = filesize($chart_path);
            
            // Phase 3: PDF
            $page_w=595;$page_h=842;$margins=50;$left=$margins;$fs=11;
            $uw=$page_w-2*$margins;
            $y=$page_h-$margins;
            
            $pages=[];$pn=1;$cp="BT /F1 {$fs} Tf\n";
            $img_obs=[];$inc=0;
            
            $np = function() use(&$cp,&$pages,&$pn,&$y,$page_h,$margins,$fs){
                $cp.=sprintf("BT /F1 9 Tf %d %d Td (Page %d) Tj ET\n",$margins,$margins-5,$pn);
                $pages[]=$cp;$pn++;$cp="BT /F1 {$fs} Tf\n";$y=$page_h-$margins;
            };
            $cpb = function($n) use(&$y,$margins,&$np){if($y-$n<$margins+30)$np();};
            
            // Title
            $cpb(30);$cp.="/F1 18 Tf\n";
            $s=str_replace(['\\','(',')'],['\\\\','\\(','\\)'],$title);
            $cp.=sprintf("%d %d Td (%s) Tj\n",$left,$y,$s);$y-=28;$cp.="/F1 {$fs} Tf\n";
            
            $dt='Generated: '.date('Y-m-d H:i:s');
            $s=str_replace(['\\','(',')'],['\\\\','\\(','\\)'],$dt);
            $cp.="/F1 9 Tf\n";$cp.=sprintf("%d %d Td (%s) Tj\n",$left,$y,$s);$y-=16;$cp.="/F1 {$fs} Tf\n";
            
            $info="Rows: {$total_rows}, chart shows {$max_rows}";
            $s=str_replace(['\\','(',')'],['\\\\','\\(','\\)'],$info);
            $cp.=sprintf("%d %d Td (%s) Tj\n",$left,$y,$s);$y-=24;
            
            // Embed chart
            $ii=@getimagesize($chart_path);
            if($ii){
                list($ow,$oh)=$ii;
                $sc=min(1.0,460/$ow);$dw=(int)($ow*$sc);$dh=(int)($oh*$sc);
                $cpb($dh+20);$inc++;$in='Im'.$inc;
                $bd_=file_get_contents($chart_path);
                $img_obs[]=['n'=>$in,'w'=>$ow,'h'=>$oh,'d'=>$bd_,'cs'=>'/DeviceRGB'];
                $ix=$left;$iy=$y-$dh;
                $cp.="q\n".sprintf("%.2f 0 0 %.2f %.2f %.2f cm\n",$dw,$dh,$ix,$iy).sprintf("/%s Do\n",$in)."Q\n";
                $y-=$dh+15;
            }
            
            // Data
            $cp.="/F1 9 Tf\n";
            for($i=0;$i<min(30,count($labels));$i++){
                $cpb(12);
                $rt=" {$labels[$i]}: {$values[$i]}";
                $s=str_replace(['\\','(',')'],['\\\\','\\(','\\)'],$rt);
                $cp.=sprintf("%d %d Td (%s) Tj\n",$left,$y,$s);$y-=12;
            }
            
            $cp.=sprintf("BT /F1 9 Tf %d %d Td (Page %d) Tj ET\n",$margins,$margins-5,$pn);
            $pages[]=$cp;$pc=count($pages);
            
            // Build PDF bytes
            $pdf="%PDF-1.4\n%\xE2\xE3\xCF\xD3\n";
            $on=0;$off=[];$no=function()use(&$on){return++$on;};
            $oc=$no();$op=$no();
            $oim=[];foreach($img_obs as $im)$oim[$im['n']]=$no();
            $of=$no();$ops=[];$oss=[];
            for($i=0;$i<$pc;$i++){$ops[]=$no();$oss[]=$no();}
            
            $off[$oc]=strlen($pdf);$pdf.="{$oc} 0 obj\n<< /Type /Catalog /Pages {$op} 0 R >>\nendobj\n";
            $ks='['.implode(' ',$ops).']';
            $off[$op]=strlen($pdf);$pdf.="{$op} 0 obj\n<< /Type /Pages /Kids {$ks} /Count {$pc} >>\nendobj\n";
            
            foreach($img_obs as $im){
