            }
            
            $off[$of]=strlen($pdf);$pdf.="{$of} 0 obj\n<< /Type /Font /Subtype /Type1 /BaseFont /Courier >>\nendobj\n";
            $xr='';foreach($img_obs as $im)$xr.="/{$im['n']} {$oim[$im['n']]} 0 R ";
            $res="<< /Font << /F1 {$of} 0 R >>".($xr?" /XObject << {$xr} >>":"")." /ProcSet [/PDF /Text /ImageC] >>";
            
            for($i=0;$i<$pc;$i++){
